meta.script:
const { record, isInit, triggerBy, set = [], that } = this;
let recordId=that.$route.query.maintenanceAssetId
let location=that.$route.query.location
if (triggerBy === "caller") {
  console.log("record:", record)
  console.log("records:", window.recordField.Incident.caller.records)
  for (let index = 0; index < window.recordField.Incident.caller.records.length; index++) {
      let tem_caller = window.recordField.Incident.caller.records[index]
      if (tem_caller.recordID === record.caller) {
         record.assignmentGroup = tem_caller.values.group[0]
      }
  }
}
if (triggerBy === "category") {
  console.log(record.category);
  console.log("records:", window.recordField.Incident.category.records)
  for (let index = 0; index < window.recordField.Incident.category.records.length; index++) {
      let tem_category = window.recordField.Incident.category.records[index]
      if (tem_category.recordID === record.category) {
         record.assignmentGroup = tem_category.values.assignmentGroup
      }
  }
}

record.maintenanceAssetId = recordId;
if(!record.location){
record.location = location;
}

return {
    record,
    triggerRecordFieldChange: ""
}
